# Create the hosted zone
resource "aws_route53_zone" "primary" {
  name = "example.com"
}

# Create CloudWatch Logs log group
resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/example.com"
  retention_in_days = 7
}

# Data source for current AWS account and region
data "aws_caller_identity" "current" {}
data "aws_region" "current" {}

# Create CloudWatch Logs resource policy to allow Route 53 to write logs
resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "${aws_cloudwatch_log_group.aws_route53_example_com.arn}:*"
        Condition = {
          StringEquals = {
            "aws:SourceAccount" = data.aws_caller_identity.current.account_id
          }
          ArnLike = {
            "aws:SourceArn" = "arn:aws:route53:::hostedzone/*"
          }
        }
      }
    ]
  })
}

# Create Route 53 query logging configuration
resource "aws_route53_query_log" "example" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

