resource "random_password" "db" {
  length  = 16
  special = false
}

# VPC and networking components required for RDS instances
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "primary" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "primary-subnet"
  }
}

resource "aws_subnet" "secondary" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "secondary-subnet"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "main-db-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.primary.id, aws_subnet.secondary.id]

  tags = {
    Name = "main-db-subnet-group"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Primary DB instance
resource "aws_db_instance" "primary" {
  identifier              = "primary-${random_id.suffix.hex}"
  allocated_storage       = 20
  engine                  = "mysql"
  engine_version          = "8.0"
  instance_class          = "db.t3.micro"
  db_name                 = "primarydb"
  username                = "admin"
  password                = random_password.db.result
  db_subnet_group_name    = aws_db_subnet_group.main.name
  skip_final_snapshot     = true
  backup_retention_period = 7
  publicly_accessible     = false

  tags = {
    Name = "primary"
  }
}

# Read Replica 1
resource "aws_db_instance" "replica_1" {
  identifier          = "replica-1-${random_id.suffix.hex}"
  replicate_source_db = aws_db_instance.primary.identifier
  instance_class      = "db.t3.micro"
  skip_final_snapshot = true
  publicly_accessible = false

  tags = {
    Name = "replica-1"
  }
}

