  name                = "eb-env"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2 v3.5.9 running Python 3.8"
  version_label       = aws_elastic_beanstalk_application_version.version.name

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Create Route 53 hosted zone
resource "aws_route53_zone" "main" {
  name = "example.com"
}

# Create Route 53 record to route traffic to Elastic Beanstalk environment
resource "aws_route53_record" "eb_alias" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.eb-env.cname
    zone_id                = "Z117KPS5GTRQ2G"  # Elastic Beanstalk hosted zone ID (varies by region)
    evaluate_target_health = false
  }
}
