# Route 53 Health Check - US West
resource "aws_route53_health_check" "us_west" {
  provider          = aws.us_west
  fqdn              = aws_elastic_beanstalk_environment.us_west.cname
  port              = 80
  type              = "HTTP"
  resource_path     = "/"
  failure_threshold = 3
  request_interval  = 30

