    Name = "eb-vpc"
  }
}

# Internet Gateway
resource "aws_internet_gateway" "eb_igw" {
  vpc_id = aws_vpc.eb_vpc.id

  tags = {
    Name = "eb-internet-gateway"
  }
}

# Subnets
resource "aws_subnet" "eb_subnet_1" {
