  name          = "sample-project"
  description   = "Sample CodeBuild project with multiple sources and artifacts"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    name = "primary-artifact"
    packaging = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "secondary-artifact-1"
    type               = "S3"
    location           = aws_s3_bucket.codebuild_artifacts.bucket
    name               = "secondary-artifact-1"
    packaging          = "ZIP"
  }

  secondary_artifacts {
    artifact_identifier = "secondary-artifact-2"
    type               = "S3"
    location           = aws_s3_bucket.codebuild_artifacts.bucket
    name               = "secondary-artifact-2"
    packaging          = "NONE"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "ENV"
      value = "production"
    }

    environment_variable {
      name  = "REGION"
      value = "us-east-1"
    }

    environment_variable {
      name  = "API_KEY"
      value = "sample-api-key-value"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "DB_PASSWORD"
      value = "/codebuild/db-password"
      type  = "PARAMETER_STORE"
    }
  }

  source {
    type            = "CODECOMMIT"
    location        = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/primary-repo"
    git_clone_depth = 1
  }

  secondary_sources {
    source_identifier = "secondary-source-1"
    type             = "CODECOMMIT"
    location         = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/secondary-repo-1"
    git_clone_depth  = 1
  }

  secondary_sources {
    source_identifier = "secondary-source-2"
    type             = "GITHUB"
    location         = "https://github.com/example/secondary-repo-2.git"
    git_clone_depth  = 1
  }

  secondary_sources {
    source_identifier = "secondary-source-3"
    type             = "CODECOMMIT"
    location         = "https://git-codecommit.us-east-1.amazonaws.com/v1/repos/secondary-repo-3"
    git_clone_depth  = 1
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "codebuild-sample-project"
      stream_name = "build-log"
    }
  }

  tags = {
    Environment = "Production"
    Project     = "Sample"
  }
}

