resource "aws_lex_intent" "book_appointment" {
  name        = "BookAppointment"
  description = "Intent to book an appointment"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to book an appointment",
    "Book an appointment",
    "Schedule an appointment",
  ]

  slot {
    name        = "AppointmentDate"
    description = "Date of the appointment"
    slot_constraint = "Required"
    slot_type   = "AMAZON.DATE"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What date would you like to schedule the appointment?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "AppointmentTime"
    description = "Time of the appointment"
    slot_constraint = "Required"
    slot_type   = "AMAZON.TIME"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What time would you like to schedule the appointment?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "ServiceType"
    description = "Type of service requested"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.service_type.name
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of service do you need?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "CustomerName"
    description = "Name of the customer"
    slot_constraint = "Required"
    slot_type   = "AMAZON.Person"
    priority    = 4

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What is your name?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, I have you down for a {ServiceType} appointment on {AppointmentDate} at {AppointmentTime}. Should I book the appointment?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I will not schedule an appointment."
      content_type = "PlainText"
    }
  }
}

