resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I would like to order a pizza",
    "Order pizza",
    "I want to order a {Size} {PizzaType} pizza",
    "Can I get a pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "Type of pizza to order"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of pizza would you like? We have cheese, pepperoni, and veggie."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Size"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like? Small, medium, or large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Crust"
    description = "Type of crust"
    slot_constraint = "Required"
    slot_type   = "AMAZON.AlphaNumeric"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What type of crust would you like? Thin, regular, or thick?"
        content_type = "PlainText"
      }

      message {
        content      = "Please choose between thin, regular, or thick crust."
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Should I order your {Size} {PizzaType} pizza with {Crust} crust?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, I have cancelled your order."
      content_type = "PlainText"
    }
  }

  follow_up_prompt {
    prompt {
      max_attempts = 2

      message {
        content      = "Would you like to add any drinks to your order?"
        content_type = "PlainText"
      }
    }

    rejection_statement {
      message {
        content      = "Okay, your order is complete. Thank you!"
        content_type = "PlainText"
      }
    }
  }
}

resource "aws_lex_bot" "pizza_ordering_bot" {
