resource "aws_lex_bot" "trip_reservations" {
  name                                = "TripReservationsBot"
  description                         = "Bot to help users book trip reservations"
  locale                              = "en-US"
  child_directed                      = false
  create_version                      = true
  detect_sentiment                    = true
  enable_model_improvements           = true
  idle_session_ttl_in_seconds         = 300
  nlu_intent_confidence_threshold     = 0.40
  process_behavior                    = "BUILD"
  voice_id                            = "Joanna"

  abort_statement {
    message {
      content      = "Sorry, I am unable to assist you with booking a trip at this time."
      content_type = "PlainText"
      group_number = 1
    }

    message {
      content      = "Please try again later or contact our support team."
      content_type = "PlainText"
      group_number = 1
    }
  }

  clarification_prompt {
    max_attempts = 3

    message {
      content      = "I'm sorry, I didn't understand that. Are you trying to book a flight, hotel, or car rental?"
      content_type = "PlainText"
      group_number = 1
    }

    message {
      content      = "Could you please clarify what type of reservation you'd like to make?"
      content_type = "PlainText"
      group_number = 1
    }

    response_card = jsonencode({
      version = 1
      contentType = "application/vnd.amazonaws.card.generic"
      genericAttachments = [
        {
          title = "What would you like to book?"
          buttons = [
            {
              text  = "Flight"
              value = "I want to book a flight"
            },
            {
              text  = "Hotel"
              value = "I want to book a hotel"
            },
            {
              text  = "Car Rental"
              value = "I want to rent a car"
            }
          ]
        }
      ]
    })
  }

  intent {
    intent_name    = "BookFlight"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = "BookHotel"
    intent_version = "$LATEST"
  }

  intent {
    intent_name    = "BookCarRental"
    intent_version = "$LATEST"
  }
}

