resource "aws_lex_intent" "order_pizza" {
  name        = "OrderPizza"
  description = "Intent to order a pizza"

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Can I get a pizza",
    "I'd like a pizza please",
    "Order pizza",
    "Pizza please",
    "I want pizza"
  ]

  slot {
    name        = "PizzaSize"
    description = "Size of the pizza"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_size.name
    slot_type_version = aws_lex_slot_type.pizza_size.version
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What size pizza would you like? We have small, medium, or large."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaTopping"
    description = "Pizza topping"
    slot_constraint = "Required"
    slot_type   = aws_lex_slot_type.pizza_topping.name
    slot_type_version = aws_lex_slot_type.pizza_topping.version
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2

      message {
        content      = "What toppings would you like? We have cheese, pepperoni, veggie, or supreme."
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Great! So you want a {PizzaSize} {PizzaTopping} pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Okay, let's start over. What kind of pizza would you like?"
      content_type = "PlainText"
    }
  }

  conclusion_statement {
    message {
      content      = "Awesome! Your {PizzaSize} {PizzaTopping} pizza is being prepared. It will be ready soon!"
      content_type = "PlainText"
    }
  }
}

