resource "aws_iam_role" "lex_bot_role" {
  name = "lex_pizza_bot_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonLexRunBotsOnly"
}

resource "aws_iam_role" "lambda_role" {
  name = "lex_pizza_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  output_path = "${path.module}/lambda_function.zip"

  source {
    content  = <<EOF
exports.handler = async (event) => {
    const intentName = event.currentIntent.name;
    const slots = event.currentIntent.slots;

    if (intentName === 'OrderPizza') {
        const pizzaType = slots.PizzaType;
        const pizzaSize = slots.PizzaSize;
        const quantity = slots.Quantity;

        return {
            dialogAction: {
                type: 'Close',
                fulfillmentState: 'Fulfilled',
                message: {
                    contentType: 'PlainText',
                    content: `Great! I've ordered ${quantity} ${pizzaSize} ${pizzaType} pizza(s) for you. Your order will be ready in 30 minutes.`
                }
            }
        };
    }

    return {
        dialogAction: {
            type: 'Close',
            fulfillmentState: 'Failed',
            message: {
                contentType: 'PlainText',
                content: 'Sorry, I could not process your order.'
            }
        }
    };
};
EOF
    filename = "index.js"
  }
}

resource "aws_lambda_function" "pizza_order" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "pizza_order_handler"
  role            = aws_iam_role.lambda_role.arn
  handler         = "index.handler"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256
  runtime         = "nodejs18.x"
  timeout         = 30
}

resource "aws_lambda_permission" "lex_invoke" {
  statement_id  = "AllowExecutionFromLex"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.pizza_order.function_name
  principal     = "lex.amazonaws.com"
}

resource "aws_lex_intent" "order_pizza" {
  name = "OrderPizza"

  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri            = aws_lambda_function.pizza_order.arn
      message_version = "1.0"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "Order pizza",
    "I'd like to order {Quantity} {PizzaSize} {PizzaType} pizza",
    "Can I get a {PizzaSize} {PizzaType} pizza"
  ]

  slot {
    name        = "PizzaType"
    description = "Type of pizza"
    slot_constraint = "Required"
    slot_type   = "PizzaType"
    priority    = 1

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like? We have Margherita, Pepperoni, Vegetarian, and Hawaiian."
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "PizzaSize"
    description = "Size of pizza"
    slot_constraint = "Required"
    slot_type   = "PizzaSize"
    priority    = 2

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What size would you like? Small, Medium, or Large?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    name        = "Quantity"
    description = "Number of pizzas"
    slot_constraint = "Required"
    slot_type   = "AMAZON.NUMBER"
    priority    = 3

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many pizzas would you like?"
        content_type = "PlainText"
      }
    }
  }
}

