resource "aws_kinesis_analytics_application" "example" {
  name = "kinesis-analytics-app"

  code = <<CODE
CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
  column1 VARCHAR(16),
  column2 INTEGER
);

CREATE OR REPLACE PUMP "STREAM_PUMP" AS 
  INSERT INTO "DESTINATION_SQL_STREAM"
    SELECT STREAM column1, column2
    FROM "SOURCE_SQL_STREAM_001";
CODE

  inputs {
    name_prefix = "SOURCE_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    parallelism {
      count = 1
    }

    schema {
      record_columns {
        mapping  = "$.column1"
        name     = "column1"
        sql_type = "VARCHAR(16)"
      }

      record_columns {
        mapping  = "$.column2"
        name     = "column2"
        sql_type = "INTEGER"
      }

      record_format {
        mapping_parameters {
          json {
            record_row_path = "$"
          }
        }
      }
    }
  }

  outputs {
    name = "DESTINATION_SQL_STREAM"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.output_stream.arn
      role_arn     = aws_iam_role.kinesis_analytics_role.arn
    }

    schema {
      record_format_type = "JSON"
    }
  }
}

