        Effect = "Allow"
        Principal = {
          Service = "kendra.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "kendra_index" {
  name = "kendra-index-policy"
  role = aws_iam_role.kendra_index.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "cloudwatch:PutMetricData"
        ]
        Resource = "*"
        Condition = {
          StringEquals = {
            "cloudwatch:namespace" = "AWS/Kendra"
          }
        }
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kendra/*"
      }
    ]
  })
}

resource "aws_kendra_index" "example" {
  name        = "example-kendra-index"
  description = "Example Kendra index with user group resolution"
  role_arn    = aws_iam_role.kendra_index.arn
  edition     = "DEVELOPER_EDITION"

  user_group_resolution_configuration {
    user_group_resolution_mode = "AWS_SSO"
  }

  tags = {
    Name        = "example-kendra-index"
    Environment = "development"
  }
}
