    Region = "eu-central-1"
  }
}

# Route 53 Traffic Policy
resource "aws_route53_traffic_policy" "load_based" {
  name     = "load-based-routing-policy"
  comment  = "Traffic policy for lowest load routing"
  document = jsonencode({
    AWSPolicyFormatVersion = "2015-10-01"
    RecordType             = "A"
    Endpoints = {
      us_east_1_endpoint = {
        Type  = "elastic-load-balancer"
        Region = "us-east-1"
        Value = aws_lb.us_east_1.dns_name
      }
      eu_central_1_endpoint = {
        Type  = "elastic-load-balancer"
        Region = "eu-central-1"
        Value = aws_lb.eu_central_1.dns_name
      }
    }
    Rules = {
      main_rule = {
        RuleType = "weighted"
        Items = [
          {
            EndpointReference = "us_east_1_endpoint"
            Weight            = "1"
            HealthCheck       = aws_route53_health_check.us_east_1.id
          },
          {
            EndpointReference = "eu_central_1_endpoint"
            Weight            = "1"
            HealthCheck       = aws_route53_health_check.eu_central_1.id
          }
        ]
      }
    }
    StartRule = "main_rule"
  })
}

