extracted_code:
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for storing application data (private)
resource "aws_s3_bucket" "private_bucket" {
  bucket = "private-app-bucket-${random_id.suffix.hex}"
}

# S3 bucket for storing logs (log-delivery writes)
resource "aws_s3_bucket" "log_bucket" {
  bucket = "log-storage-bucket-${random_id.suffix.hex}"
}

# Disable ACLs and use bucket policies for the private bucket
resource "aws_s3_bucket_ownership_controls" "private_bucket" {
  bucket = aws_s3_bucket.private_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Enable ACLs for the log bucket to allow log delivery
resource "aws_s3_bucket_ownership_controls" "log_bucket" {
  bucket = aws_s3_bucket.log_bucket.id

  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

# Private ACL for the private bucket
resource "aws_s3_bucket_acl" "private_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.private_bucket]
  bucket     = aws_s3_bucket.private_bucket.id
  acl        = "private"
}

# Log-delivery-write ACL for the log bucket
resource "aws_s3_bucket_acl" "log_bucket" {
  depends_on = [aws_s3_bucket_ownership_controls.log_bucket]
  bucket     = aws_s3_bucket.log_bucket.id
  acl        = "log-delivery-write"
}

# Enable logging on the private bucket to deliver logs to the log bucket
resource "aws_s3_bucket_logging" "private_bucket_logging" {
  bucket = aws_s3_bucket.private_bucket.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "app-logs/"
}

