# Provider configuration
provider "aws" {
  region = "us-east-1"
}

provider "aws" {
  alias  = "destination"
  region = "us-east-2"
}

# Random password for cluster
resource "random_password" "redshift" {
  length  = 16
  special = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Primary Redshift cluster in us-east-1
resource "aws_redshift_cluster" "primary" {
  provider = aws

  cluster_identifier  = "redshift-cluster-primary"
  database_name       = "mydb"
  master_username     = "admin"
  master_password     = random_password.redshift.result
  node_type           = "dc2.large"
  cluster_type        = "multi-node"
  number_of_nodes     = 2
  skip_final_snapshot = true
  publicly_accessible = false

  # Enable snapshots for replication
  automated_snapshot_retention_period = 1
}

# Snapshot copy grant for cross-region replication
resource "aws_redshift_snapshot_copy_grant" "grant" {
  provider = aws.destination

  snapshot_copy_grant_name = "redshift-copy-grant"
}

# Configure snapshot copy to us-east-2
resource "aws_redshift_snapshot_schedule" "schedule" {
  provider = aws

  identifier = "redshift-snapshot-schedule"
  definitions = [
    "rate(12 hours)"
  ]
}

resource "aws_redshift_snapshot_schedule_association" "association" {
  provider = aws

  cluster_identifier  = aws_redshift_cluster.primary.id
  schedule_identifier = aws_redshift_snapshot_schedule.schedule.id
}

# Enable cross-region snapshot copy
resource "null_resource" "enable_snapshot_copy" {
  provisioner "local-exec" {
    command = <<EOT
aws redshift enable-snapshot-copy \n  --cluster-identifier ${aws_redshift_cluster.primary.cluster_identifier} \n  --destination-region us-east-2 \n  --retention-period 7 \n  --snapshot-copy-grant-name ${aws_redshift_snapshot_copy_grant.grant.snapshot_copy_grant_name} \n  --region us-east-1
EOT
  }

  depends_on = [
    aws_redshift_cluster.primary,
    aws_redshift_snapshot_copy_grant.grant
  ]
}

output "primary_cluster_endpoint" {
  value = aws_redshift_cluster.primary.endpoint
}

output "primary_cluster_id" {
  value = aws_redshift_cluster.primary.id
}

output "master_password" {
  value     = random_password.redshift.result
  sensitive = true
}

