  name                = "every-15-minutes"
  description         = "Trigger Lambda every 15 minutes"
  schedule_expression = "rate(15 minutes)"
}

# CloudWatch Event Target
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.every_15_minutes.name
  target_id = "lambda"
  arn       = aws_lambda_function.scheduled_function.arn
}

# Lambda permission to allow CloudWatch to invoke the function
resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.scheduled_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.every_15_minutes.arn
}

