# Data source to get the most recent Amazon Linux 2 AMI
data "aws_ami" "amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }

  filter {
    name   = "virtualization-type"
    values = ["hvm"]
  }
}

# VPC for the subnets
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "main-vpc"
  }
}

# Subnet in us-east-1a
resource "aws_subnet" "subnet_1a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "subnet-us-east-1a"
  }
}

# Subnet in us-east-1b
resource "aws_subnet" "subnet_1b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "subnet-us-east-1b"
  }
}

# EC2 instance in us-east-1a
resource "aws_instance" "instance_1a" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_1a.id

  root_block_device {
    volume_size = 50
    volume_type = "gp2"
  }

  tags = {
    Name = "instance-us-east-1a"
  }
}

# EC2 instance in us-east-1b
resource "aws_instance" "instance_1b" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t2.micro"
  subnet_id     = aws_subnet.subnet_1b.id

  root_block_device {
    volume_size = 50
    volume_type = "gp2"
  }

  tags = {
    Name = "instance-us-east-1b"
  }
}

