    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "efs-sg"
  }
}

# EFS File System
resource "aws_efs_file_system" "main" {
  creation_token = "efs-shared-storage"
  encrypted      = true

  tags = {
    Name = "shared-efs"
  }
}

# EFS Mount Targets
resource "aws_efs_mount_target" "az1" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.private_1.id
  security_groups = [aws_security_group.efs.id]
}

resource "aws_efs_mount_target" "az2" {
  file_system_id  = aws_efs_file_system.main.id
  subnet_id       = aws_subnet.private_2.id
  security_groups = [aws_security_group.efs.id]
}

# IAM Role for EC2 Instances
resource "aws_iam_role" "ec2_role" {
  name = "ec2-efs-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "ssm_policy" {
  role       = aws_iam_role.ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "ec2-efs-profile"
  role = aws_iam_role.ec2_role.name
}

# EC2 Instance 1
resource "aws_instance" "instance_1" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_1.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir -p /mnt/efs
              mount -t efs -o tls ${aws_efs_file_system.main.id}:/ /mnt/efs
              echo "${aws_efs_file_system.main.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              EOF

  depends_on = [aws_efs_mount_target.az1]

  tags = {
    Name = "ec2-instance-1"
  }
}

# EC2 Instance 2
resource "aws_instance" "instance_2" {
  ami                    = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.private_2.id
  vpc_security_group_ids = [aws_security_group.ec2.id]
  iam_instance_profile   = aws_iam_instance_profile.ec2_profile.name

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y amazon-efs-utils
              mkdir -p /mnt/efs
              mount -t efs -o tls ${aws_efs_file_system.main.id}:/ /mnt/efs
              echo "${aws_efs_file_system.main.id}:/ /mnt/efs efs _netdev,tls 0 0" >> /etc/fstab
              EOF

  depends_on = [aws_efs_mount_target.az2]

  tags = {
    Name = "ec2-instance-2"
  }
}

# Outputs
output "efs_file_system_id" {
  value       = aws_efs_file_system.main.id
  description = "The ID of the EFS file system"
}

output "instance_1_id" {
  value       = aws_instance.instance_1.id
  description = "The ID of EC2 instance 1"
}

output "instance_2_id" {
  value       = aws_instance.instance_2.id
  description = "The ID of EC2 instance 2"
}
```

