# ElastiCache Redis Replication Group with IAM authentication enabled
resource "aws_elasticache_replication_group" "example" {
  replication_group_id       = "redis-iam-auth"
  description                = "Redis cluster with IAM authentication"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  parameter_group_name       = "default.redis7"
  port                       = 6379
  transit_encryption_enabled = true
  at_rest_encryption_enabled = true
  auth_token_enabled         = false

  # Enable IAM authentication
  user_group_ids = [aws_elasticache_user_group.example.id]
}

# ElastiCache User with IAM authentication
resource "aws_elasticache_user" "iam_user" {
  user_id       = "iam-user-example"
  user_name     = "iam-user-example"
  access_string = "on ~* &* +@all"
  engine        = "REDIS"

  # Enable IAM authentication for this user
  authentication_mode {
    type = "iam"
  }
}

# ElastiCache User with password authentication (default user)
resource "aws_elasticache_user" "default_user" {
  user_id       = "default-user"
  user_name     = "default"
  access_string = "on ~* &* +@all"
  engine        = "REDIS"

  authentication_mode {
    type      = "password"
    passwords = ["Password123456789"]
  }
}

# ElastiCache User Group
resource "aws_elasticache_user_group" "example" {
  user_group_id = "iam-user-group"
  engine        = "REDIS"
  user_ids      = [aws_elasticache_user.iam_user.user_id, aws_elasticache_user.default_user.user_id]
}

# IAM Role for EC2 instance to authenticate with ElastiCache
resource "aws_iam_role" "elasticache_client" {
  name = "elasticache-client-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for ElastiCache IAM authentication
resource "aws_iam_role_policy" "elasticache_iam_auth" {
  name = "elasticache-iam-auth-policy"
  role = aws_iam_role.elasticache_client.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticache:Connect"
        ]
        Resource = [
          "arn:aws:elasticache:*:*:user:${aws_elasticache_user.iam_user.user_id}"
        ]
      }
    ]
  })
}

