# VPC and Networking
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "neptune-vpc"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "neptune-subnet-1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"

  tags = {
    Name = "neptune-subnet-2"
  }
}

# Neptune Subnet Group
resource "aws_neptune_subnet_group" "main" {
  name       = "neptune-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]

  tags = {
    Name = "neptune-subnet-group"
  }
}

# Neptune Cluster Parameter Group
resource "aws_neptune_cluster_parameter_group" "main" {
  family      = "neptune1.2"
  name        = "neptune-custom-params"
  description = "Custom parameter group for Neptune cluster"

  parameter {
    name  = "neptune_enable_audit_log"
    value = "1"
  }

  tags = {
    Name = "neptune-custom-params"
  }
}

# Security Group
resource "aws_security_group" "neptune" {
  name        = "neptune-sg"
  description = "Security group for Neptune cluster - restricted to specific subnets"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "Neptune access from subnet 1"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet1.cidr_block]
  }

  ingress {
    description = "Neptune access from subnet 2"
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.subnet2.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "neptune-sg"
  }
}

# Neptune Cluster
