resource "aws_iam_role" "chime_kinesis" {
  name = "chime-kinesis-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "mediapipelines.chime.amazonaws.com"
        }
      }
    ]
  })
}

