# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograder-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.grading_results.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = aws_s3_bucket.grading_results.arn
      }
    ]
  })
}

# S3 bucket for storing grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "autograder-results-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket versioning
resource "aws_s3_bucket_versioning" "grading_results_versioning" {
  bucket = aws_s3_bucket.grading_results.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "student-autograder"
  description   = "Automated grading system for student submissions"
  build_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:7.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }

    environment_variable {
      name  = "STUDENT_REPO"
      value = "PLACEHOLDER"
      type  = "PLAINTEXT"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      stream_name = "build-log"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/student-org/student-repo.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2

      phases:
        install:
          runtime-versions:
            python: 3.11
          commands:
            - echo "Installing dependencies..."
            - pip install pytest pytest-json-report

        pre_build:
          commands:
            - echo "Preparing test environment..."
            - STUDENT_ID=$(echo $CODEBUILD_SOURCE_VERSION | cut -d'/' -f3)
            - TIMESTAMP=$(date +%Y%m%d_%H%M%S)

        build:
          commands:
            - echo "Running autograder tests..."
            - pytest --json-report --json-report-file=results.json || true

        post_build:
          commands:
            - echo "Processing results..."
            - |
              cat > grading_report.json <<EOF
              {
                "student_id": "$STUDENT_ID",
                "timestamp": "$TIMESTAMP",
                "commit": "$CODEBUILD_RESOLVED_SOURCE_VERSION",
                "results_file": "results.json"
              }
              EOF
            - aws s3 cp results.json s3://$RESULTS_BUCKET/$STUDENT_ID/$TIMESTAMP/results.json
            - aws s3 cp grading_report.json s3://$RESULTS_BUCKET/$STUDENT_ID/$TIMESTAMP/grading_report.json
            - echo "Grading complete. Results uploaded to S3."

      artifacts:
        files:
          - results.json
          - grading_report.json
    EOT
  }

  source_version = "main"
}

