  name = "autograder-notifications"
}

# EventBridge rule to monitor CodeBuild completion
resource "aws_cloudwatch_event_rule" "codebuild_completion" {
  name        = "autograder-completion"
  description = "Trigger on CodeBuild completion"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
      build-status = ["SUCCEEDED", "FAILED"]
    }
  })
}

