        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          "${aws_s3_bucket.autograder_storage.arn}",
          "${aws_s3_bucket.autograder_storage.arn}/*",
          "${aws_s3_bucket.codebuild_artifacts.arn}",
          "${aws_s3_bucket.codebuild_artifacts.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:GetItem"
        ]
        Resource = aws_dynamodb_table.submissions.arn
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Automated grading system for student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 15

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.codebuild_artifacts.bucket
    packaging = "ZIP"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:7.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "GRADING_BUCKET"
      value = aws_s3_bucket.autograder_storage.bucket
    }

    environment_variable {
      name  = "SUBMISSIONS_TABLE"
      value = aws_dynamodb_table.submissions.name
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/student-repo-placeholder.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          commands:
            - echo Installing test dependencies...
            - pip install pytest pytest-json-report pylint
        pre_build:
          commands:
            - echo Preparing test environment...
            - export SUBMISSION_ID=$(date +%s)
        build:
          commands:
            - echo Running tests and grading...
            - pytest --json-report --json-report-file=test_results.json || true
            - pylint **/*.py --output-format=json > lint_results.json || true
        post_build:
          commands:
            - echo Uploading results to S3...
            - aws s3 cp test_results.json s3://$GRADING_BUCKET/results/$SUBMISSION_ID/
            - aws s3 cp lint_results.json s3://$GRADING_BUCKET/results/$SUBMISSION_ID/
            - echo Recording submission in DynamoDB...
            - |
              aws dynamodb put-item --table-name $SUBMISSIONS_TABLE \n                --item "{"submission_id": {"S": "$SUBMISSION_ID"}, "timestamp": {"N": "$(date +%s)"}, "student_id": {"S": "$STUDENT_ID"}, "status": {"S": "completed"}}"
      artifacts:
        files:
          - test_results.json
          - lint_results.json
    EOT
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      stream_name = "build-log"
    }
  }
}

# Lambda execution role
resource "aws_iam_role" "lambda_role" {
  name = "autograder-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Lambda policy
resource "aws_iam_role_policy" "lambda_policy" {
  role = aws_iam_role.lambda_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem"
        ]
        Resource = aws_dynamodb_table.submissions.arn
      }
    ]
  })
}

# Lambda function to trigger autograding
resource "aws_lambda_function" "trigger_autograder" {
  filename      = "lambda_function.zip"
  function_name = "autograder-trigger"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograder.name
      SUBMISSIONS_TABLE = aws_dynamodb_table.submissions.name
    }
  }
}

# SNS topic for grading notifications
resource "aws_sns_topic" "grading_notifications" {
  name = "autograder-notifications"
}

# EventBridge rule to monitor CodeBuild completion
resource "aws_cloudwatch_event_rule" "codebuild_completion" {
  name        = "autograder-completion"
  description = "Trigger on CodeBuild completion"

  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      project-name = [aws_codebuild_project.autograder.name]
      build-status = ["SUCCEEDED", "FAILED"]
    }
  })
}

# EventBridge target for SNS
resource "aws_cloudwatch_event_target" "sns" {
  rule      = aws_cloudwatch_event_rule.codebuild_completion.name
  target_id = "SendToSNS"
  arn       = aws_sns_topic.grading_notifications.arn
}

# SNS topic policy
resource "aws_sns_topic_policy" "grading_notifications" {
  arn = aws_sns_topic.grading_notifications.arn

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
        Action   = "SNS:Publish"
        Resource = aws_sns_topic.grading_notifications.arn
      }
    ]
  })
}

# Output important values
output "s3_storage_bucket" {
  value       = aws_s3_bucket.autograder_storage.bucket
  description = "S3 bucket for storing grading results"
}

output "codebuild_project_name" {
  value       = aws_codebuild_project.autograder.name
  description = "CodeBuild project name for autograding"
}

output "dynamodb_table_name" {
  value       = aws_dynamodb_table.submissions.name
  description = "DynamoDB table for tracking submissions"
}

output "lambda_function_name" {
  value       = aws_lambda_function.trigger_autograder.function_name
  description = "Lambda function to trigger autograding"
}

output "sns_topic_arn" {
  value       = aws_sns_topic.grading_notifications.arn
  description = "SNS topic for grading notifications"
}
```

