# VPC for isolated code execution
resource "aws_vpc" "autograding_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "autograding-vpc"
  }
}

# Private subnets for CodeBuild (no internet access)
resource "aws_subnet" "private_subnet_1" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "autograding-private-subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id            = aws_vpc.autograding_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "autograding-private-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for CodeBuild - no outbound internet access
resource "aws_security_group" "codebuild_sg" {
  name        = "autograding-codebuild-sg"
  description = "Security group for autograding CodeBuild - no internet access"
  vpc_id      = aws_vpc.autograding_vpc.id

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.0.0/16"]
    description = "Allow traffic only within VPC"
  }

  tags = {
    Name = "autograding-codebuild-sg"
  }
}

# S3 bucket for storing grading results
resource "aws_s3_bucket" "grading_results" {
  bucket = "autograding-results-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "autograding-results"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 4
}

resource "aws_s3_bucket_versioning" "grading_results_versioning" {
  bucket = aws_s3_bucket.grading_results.id

  versioning_configuration {
    status = "Enabled"
  }
}

# DynamoDB table for storing grading outcomes
resource "aws_dynamodb_table" "grading_outcomes" {
  name           = "autograding-outcomes"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "SubmissionId"
  range_key      = "Timestamp"

  attribute {
    name = "SubmissionId"
    type = "S"
  }

  attribute {
    name = "Timestamp"
    type = "N"
  }

  attribute {
    name = "StudentId"
    type = "S"
  }

  global_secondary_index {
    name            = "StudentIdIndex"
    hash_key        = "StudentId"
    range_key       = "Timestamp"
    projection_type = "ALL"
  }

  tags = {
    Name = "autograding-outcomes"
  }
}

# VPC Endpoint for S3 (to allow CodeBuild to access S3 without internet)
