data "aws_caller_identity" "current" {}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding" {
  name          = "autograding-project"
  description   = "Autograding system for student submissions"
  build_timeout = 30
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.id
    }

    environment_variable {
      name  = "DYNAMODB_TABLE"
      value = aws_dynamodb_table.grading_outcomes.name
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/example/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        install:
          commands:
            - echo "Installing dependencies..."
        build:
          commands:
            - echo "Running autograder..."
            - echo "Submission ID:$SUBMISSION_ID Student ID:$STUDENT_ID"
            - |
              # Run student code here (example)
              # ./run_tests.sh > results.txt 2>&1
              TIMESTAMP=$(date +%s)
              SCORE=95
              echo "{"SubmissionId":"$SUBMISSION_ID","Timestamp":$TIMESTAMP,"StudentId":"$STUDENT_ID","Score":$SCORE,"Status":"COMPLETED"}" > grading_result.json
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - aws s3 cp grading_result.json s3://$RESULTS_BUCKET/$STUDENT_ID/$SUBMISSION_ID/result.json
            - echo "Recording outcome to DynamoDB..."
            - aws dynamodb put-item --table-name $DYNAMODB_TABLE --item file://grading_result.json
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/autograding"
      stream_name = "build-logs"
    }
  }

  tags = {
    Name = "autograding-codebuild-project"
  }
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograding"
  retention_in_days = 30

  tags = {
    Name = "autograding-logs"
  }
}

# Output values
output "codebuild_project_name" {
  value       = aws_codebuild_project.autograding.name
  description = "Name of the CodeBuild project"
}

output "grading_results_bucket" {
  value       = aws_s3_bucket.grading_results.id
  description = "S3 bucket for grading results"
}

output "grading_outcomes_table" {
  value       = aws_dynamodb_table.grading_outcomes.name
  description = "DynamoDB table for grading outcomes"
}

output "vpc_id" {
  value       = aws_vpc.autograding_vpc.id
  description = "VPC ID for isolated execution"
}

