resource "aws_s3_bucket_public_access_block" "test_cases_pab" {
  bucket = aws_s3_bucket.test_cases.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# CloudWatch Log Group for autograder logs
resource "aws_cloudwatch_log_group" "autograder_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30

  tags = {
    Name = "autograder-logs"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "autograder-codebuild-role"
  }
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = [
          "${aws_cloudwatch_log_group.autograder_logs.arn}",
          "${aws_cloudwatch_log_group.autograder_logs.arn}:*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:GetObjectVersion"
        ]
        Resource = [
          "${aws_s3_bucket.submissions.arn}/*",
          "${aws_s3_bucket.test_cases.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject"
        ]
        Resource = [
          "${aws_s3_bucket.results.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.submissions.arn,
          aws_s3_bucket.results.arn,
          aws_s3_bucket.test_cases.arn
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograder for student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_MEDIUM"
    image                       = "aws/codebuild/standard:7.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = false

    environment_variable {
      name  = "SUBMISSIONS_BUCKET"
      value = aws_s3_bucket.submissions.id
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.results.id
    }

    environment_variable {
      name  = "TEST_CASES_BUCKET"
      value = aws_s3_bucket.test_cases.id
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.autograder_logs.name
      status      = "ENABLED"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/placeholder/student-submissions.git"
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          commands:
            - echo "Installing dependencies..."
            - apt-get update
        pre_build:
          commands:
            - echo "Downloading test cases from S3..."
            - aws s3 cp s3://$TEST_CASES_BUCKET/test_suite.py ./test_suite.py
            - aws s3 cp s3://$TEST_CASES_BUCKET/requirements.txt ./requirements.txt
            - pip install -r requirements.txt
        build:
          commands:
            - echo "Running autograder tests..."
            - python test_suite.py > results.txt 2>&1 || true
            - echo "Grading completed"
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - TIMESTAMP=$(date +%Y%m%d-%H%M%S)
            - SUBMISSION_ID=$(echo $CODEBUILD_SOURCE_VERSION | cut -c1-7)
            - aws s3 cp results.txt s3://$RESULTS_BUCKET/$SUBMISSION_ID-$TIMESTAMP-results.txt
            - echo "Results uploaded successfully"
    EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "autograder-project"
  }
}

# EventBridge rule to trigger CodeBuild on S3 upload
resource "aws_cloudwatch_event_rule" "s3_upload" {
  name        = "autograder-s3-upload-trigger"
  description = "Trigger autograder when new submission uploaded to S3"

  event_pattern = jsonencode({
    source      = ["aws.s3"]
    detail-type = ["Object Created"]
    detail = {
      bucket = {
        name = [aws_s3_bucket.submissions.id]
      }
    }
  })
}

# IAM role for EventBridge
resource "aws_iam_role" "eventbridge_role" {
  name = "autograder-eventbridge-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "events.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "eventbridge_policy" {
  role = aws_iam_role.eventbridge_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "codebuild:StartBuild"
        ]
        Resource = aws_codebuild_project.autograder.arn
      }
    ]
  })
}

# EventBridge target to start CodeBuild
resource "aws_cloudwatch_event_target" "codebuild" {
  rule      = aws_cloudwatch_event_rule.s3_upload.name
  target_id = "TriggerCodeBuild"
  arn       = aws_codebuild_project.autograder.arn
  role_arn  = aws_iam_role.eventbridge_role.arn
}

# Enable EventBridge notifications for S3 bucket
resource "aws_s3_bucket_notification" "submissions_notification" {
  bucket      = aws_s3_bucket.submissions.id
  eventbridge = true
}

# Random ID for unique resource naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
}

data "aws_region" "current" {}

# Outputs
output "submissions_bucket_name" {
  description = "Name of the S3 bucket for student submissions"
  value       = aws_s3_bucket.submissions.id
}

output "results_bucket_name" {
  description = "Name of the S3 bucket for grading results"
  value       = aws_s3_bucket.results.id
}

output "test_cases_bucket_name" {
  description = "Name of the S3 bucket for test cases"
  value       = aws_s3_bucket.test_cases.id
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograder.name
}

output "vpc_id" {
  description = "ID of the isolated VPC"
  value       = aws_vpc.autograder_vpc.id
}

output "log_group_name" {
  description = "CloudWatch Log Group for autograder logs"
  value       = aws_cloudwatch_log_group.autograder_logs.name
}
