resource "aws_security_group" "vpc_endpoints" {
  name        = "autograder-vpc-endpoints-sg"
  description = "Security group for VPC endpoints"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.autograder_vpc.cidr_block]
    description = "HTTPS from VPC"
  }

  tags = {
    Name = "autograder-vpc-endpoints-sg"
  }
}

# Route table for private subnet (no internet gateway)
resource "aws_route_table" "private" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "autograder-private-rt"
  }
}

# Route table association
resource "aws_route_table_association" "private" {
  subnet_id      = aws_subnet.autograder_private_subnet.id
  route_table_id = aws_route_table.private.id
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograder-codebuild-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for CodeBuild
resource "aws_iam_role_policy" "codebuild_policy" {
  role = aws_iam_role.codebuild_role.name

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:${data.aws_region.current.name}:${data.aws_caller_identity.current.account_id}:log-group:/aws/codebuild/*"
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.grading_results.arn,
          "${aws_s3_bucket.grading_results.arn}/*",
          aws_s3_bucket.codebuild_cache.arn,
          "${aws_s3_bucket.codebuild_cache.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeVpcs",
          "ec2:CreateNetworkInterfacePermission"
        ]
        Resource = "*"
      }
    ]
  })
}

# CloudWatch Log Group for CodeBuild
resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograder"
  retention_in_days = 30

  tags = {
    Name = "autograder-logs"
  }
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograder" {
  name          = "autograder-project"
  description   = "Autograding system for CS course submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = 30

  artifacts {
    type = "NO_ARTIFACTS"
  }

  cache {
    type     = "S3"
    location = aws_s3_bucket.codebuild_cache.bucket
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                      = "aws/codebuild/standard:5.0"
    type                       = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = aws_s3_bucket.grading_results.bucket
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = aws_cloudwatch_log_group.codebuild_logs.name
      status      = "ENABLED"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/YOUR_ORG/student-submissions.git"
    git_clone_depth = 1
    buildspec       = <<-EOT
      version: 0.2
      phases:
        pre_build:
          commands:
            - echo "Starting autograder for submission"
        build:
          commands:
            - echo "Running tests on student code"
            - chmod +x ./run_tests.sh
            - ./run_tests.sh > test_results.txt 2>&1
        post_build:
          commands:
            - echo "Uploading results to S3"
            - |
              TIMESTAMP=$(date +%Y%m%d_%H%M%S)
              SUBMISSION_ID=$${CODEBUILD_RESOLVED_SOURCE_VERSION:0:7}
              aws s3 cp test_results.txt s3://$${RESULTS_BUCKET}/results/$${SUBMISSION_ID}_$${TIMESTAMP}.txt
      EOT
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_private_subnet.id]
    security_group_ids = [aws_security_group.autograder_sg.id]
  }

  tags = {
    Name = "autograder-project"
  }
}

# Random ID for unique S3 bucket names
resource "random_id" "bucket_suffix" {
  byte_length = 4
}

# Data sources
data "aws_region" "current" {}

data "aws_caller_identity" "current" {}

data "aws_availability_zones" "available" {
  state = "available"
}
```

