# S3 bucket for storing cat images
resource "aws_s3_bucket" "cat_images" {
  bucket_prefix = "cat-images-"
}

# S3 bucket public access block configuration
resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# S3 bucket policy to allow public read access
resource "aws_s3_bucket_policy" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.cat_images.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.cat_images]
}

# S3 bucket CORS configuration
resource "aws_s3_bucket_cors_configuration" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  cors_rule {
    allowed_headers = ["*"]
    allowed_methods = ["GET", "PUT", "POST"]
    allowed_origins = ["*"]
    expose_headers  = ["ETag"]
    max_age_seconds = 3000
  }
}

# IAM role for API Gateway
resource "aws_iam_role" "api_gateway" {
  name_prefix = "cat-app-api-gateway-"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "apigateway.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for API Gateway to access S3
resource "aws_iam_role_policy" "api_gateway_s3" {
  name_prefix = "s3-access-"
  role        = aws_iam_role.api_gateway.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      }
    ]
  })
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_app" {
  name        = "cat-images-api"
  description = "API for uploading and retrieving cat images"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

# API Gateway resource for upload
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  parent_id   = aws_api_gateway_rest_api.cat_app.root_resource_id
  path_part   = "upload"
}

# API Gateway resource for random cat
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  parent_id   = aws_api_gateway_rest_api.cat_app.root_resource_id
  path_part   = "random"
}

# API Gateway resource for upload with filename
resource "aws_api_gateway_resource" "upload_filename" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  parent_id   = aws_api_gateway_resource.upload.id
  path_part   = "{filename}"
}

# PUT method for uploading images
resource "aws_api_gateway_method" "upload_put" {
  rest_api_id   = aws_api_gateway_rest_api.cat_app.id
  resource_id   = aws_api_gateway_resource.upload_filename.id
  http_method   = "PUT"
  authorization = "NONE"

  request_parameters = {
    "method.request.path.filename"       = true
    "method.request.header.Content-Type" = false
  }
}

# GET method for retrieving random cat image
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_app.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

# Integration for upload PUT method
resource "aws_api_gateway_integration" "upload_s3" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.upload_filename.id
  http_method = aws_api_gateway_method.upload_put.http_method

  type                    = "AWS"
  integration_http_method = "PUT"
  credentials             = aws_iam_role.api_gateway.arn
  uri                     = "arn:aws:apigateway:${data.aws_region.current.name}:s3:path/${aws_s3_bucket.cat_images.bucket}/{filename}"

  request_parameters = {
    "integration.request.path.filename" = "method.request.path.filename"
  }
}

# Integration response for upload
resource "aws_api_gateway_integration_response" "upload_response" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.upload_filename.id
  http_method = aws_api_gateway_method.upload_put.http_method
  status_code = aws_api_gateway_method_response.upload_200.status_code

  depends_on = [aws_api_gateway_integration.upload_s3]
}

# Method response for upload
resource "aws_api_gateway_method_response" "upload_200" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.upload_filename.id
  http_method = aws_api_gateway_method.upload_put.http_method
  status_code = "200"

  response_parameters = {
    "method.response.header.Access-Control-Allow-Origin" = true
  }
}

# Mock integration for random cat (returns redirect to S3)
resource "aws_api_gateway_integration" "random_mock" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method

  type = "MOCK"

  request_templates = {
    "application/json" = "{"statusCode": 302}"
  }
}

# Integration response for random cat
resource "aws_api_gateway_integration_response" "random_response" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method
  status_code = aws_api_gateway_method_response.random_302.status_code

  response_parameters = {
    "method.response.header.Location" = "'https://${aws_s3_bucket.cat_images.bucket}.s3.${data.aws_region.current.name}.amazonaws.com/'"
  }

  depends_on = [aws_api_gateway_integration.random_mock]
}

# Method response for random cat
resource "aws_api_gateway_method_response" "random_302" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id
  resource_id = aws_api_gateway_resource.random.id
  http_method = aws_api_gateway_method.random_get.http_method
  status_code = "302"

  response_parameters = {
    "method.response.header.Location" = true
  }
}

# API Gateway deployment
resource "aws_api_gateway_deployment" "cat_app" {
  rest_api_id = aws_api_gateway_rest_api.cat_app.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.upload_put.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.upload_s3.id,
      aws_api_gateway_integration.random_mock.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }

  depends_on = [
    aws_api_gateway_integration.upload_s3,
    aws_api_gateway_integration.random_mock,
    aws_api_gateway_integration_response.upload_response,
    aws_api_gateway_integration_response.random_response
  ]
}

# API Gateway stage
resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_app.id
  rest_api_id   = aws_api_gateway_rest_api.cat_app.id
  stage_name    = "prod"
}

# Data source for current region
data "aws_region" "current" {}

# Outputs
output "api_endpoint" {
  description = "API Gateway endpoint URL"
  value       = aws_api_gateway_stage.prod.invoke_url
}

output "s3_bucket_name" {
