```hcl
# Random suffix for unique resource naming
resource "random_id" "suffix" {
  byte_length = 4
}

# S3 bucket for storing cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-images-bucket-${random_id.suffix.hex}"
}

# S3 bucket versioning
resource "aws_s3_bucket_versioning" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id
  versioning_configuration {
    status = "Enabled"
  }
}

# S3 bucket public access block
resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

# S3 bucket policy for public read access to images
resource "aws_s3_bucket_policy" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.cat_images.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.cat_images]
}

# IAM role for Lambda functions
resource "aws_iam_role" "lambda_role" {
  name = "cat-api-lambda-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda to access S3 and CloudWatch Logs
resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat-api-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lambda function for uploading cat images
resource "aws_lambda_function" "upload_cat" {
  filename      = "upload_cat.zip"
  function_name = "upload-cat-image-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.bucket
    }
  }
}

# Lambda function for retrieving random cat images
resource "aws_lambda_function" "get_random_cat" {
  filename      = "get_random_cat.zip"
  function_name = "get-random-cat-image-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME = aws_s3_bucket.cat_images.bucket
    }
  }
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "cat-image-api-${random_id.suffix.hex}"
  description = "API for uploading and retrieving cat images"

  binary_media_types = ["image/jpeg", "image/png", "image/jpg"]
}

# API Gateway resource for /upload
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "upload"
}

# API Gateway resource for /random
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  parent_id   = aws_api_gateway_rest_api.cat_api.root_resource_id
  path_part   = "random"
}

# API Gateway method for POST /upload
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"
}

# API Gateway method for GET /random
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

# API Gateway integration for upload Lambda
resource "aws_api_gateway_integration" "upload_lambda" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.upload.id
  http_method             = aws_api_gateway_method.upload_post.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.upload_cat.invoke_arn
}

# API Gateway integration for random cat Lambda
resource "aws_api_gateway_integration" "random_lambda" {
  rest_api_id             = aws_api_gateway_rest_api.cat_api.id
  resource_id             = aws_api_gateway_resource.random.id
  http_method             = aws_api_gateway_method.random_get.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.get_random_cat.invoke_arn
}

# Lambda permission for API Gateway to invoke upload function
resource "aws_lambda_permission" "apigw_upload" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# Lambda permission for API Gateway to invoke random function
resource "aws_lambda_permission" "apigw_random" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.get_random_cat.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# API Gateway deployment
resource "aws_api_gateway_deployment" "cat_api" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.upload_post.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.upload_lambda.id,
      aws_api_gateway_integration.random_lambda.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }
}

# API Gateway stage
resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_api.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

# CloudWatch Log Group for API Gateway
resource "aws_cloudwatch_log_group" "api_gateway" {
  name              = "/aws/apigateway/cat-api-${random_id.suffix.hex}"
  retention_in_days = 7
}

# Output the API endpoint
output "api_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}"
  description = "API Gateway endpoint URL"
}

output "upload_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/upload"
  description = "Endpoint for uploading cat images"
}

output "random_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/random"
  description = "Endpoint for getting random cat images"
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.cat_images.bucket
  description = "S3 bucket name for cat images"
}
