# DynamoDB table for storing cat image metadata
resource "aws_dynamodb_table" "cat_images" {
  name           = "cat-images-table"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "image_id"

  attribute {
    name = "image_id"
    type = "S"
  }

  tags = {
    Name = "cat-images-table"
  }
}

# S3 bucket for storing cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "cat-images-bucket-${random_id.bucket_suffix.hex}"

  tags = {
    Name = "cat-images-bucket"
  }
}

resource "random_id" "bucket_suffix" {
  byte_length = 8
}

resource "aws_s3_bucket_public_access_block" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_policy" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "PublicReadGetObject"
        Effect    = "Allow"
        Principal = "*"
        Action    = "s3:GetObject"
        Resource  = "${aws_s3_bucket.cat_images.arn}/*"
      }
    ]
  })

  depends_on = [aws_s3_bucket_public_access_block.cat_images]
}

# IAM role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "cat-images-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda to access S3 and DynamoDB
resource "aws_iam_role_policy" "lambda_policy" {
  name = "cat-images-lambda-policy"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Scan",
          "dynamodb:Query"
        ]
        Resource = aws_dynamodb_table.cat_images.arn
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# Lambda function
resource "aws_lambda_function" "cat_images" {
  filename      = "lambda_function.zip"
  function_name = "cat-images-handler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.9"
  timeout       = 30

  environment {
    variables = {
      BUCKET_NAME      = aws_s3_bucket.cat_images.bucket
      DYNAMODB_TABLE   = aws_dynamodb_table.cat_images.name
    }
  }

  depends_on = [aws_iam_role_policy.lambda_policy]
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_images" {
  name        = "cat-images-api"
  description = "API for uploading and retrieving cat images"

  endpoint_configuration {
    types = ["REGIONAL"]
  }
}

# API Gateway resource for upload
resource "aws_api_gateway_resource" "upload" {
  rest_api_id = aws_api_gateway_rest_api.cat_images.id
  parent_id   = aws_api_gateway_rest_api.cat_images.root_resource_id
  path_part   = "upload"
}

# API Gateway resource for random
resource "aws_api_gateway_resource" "random" {
  rest_api_id = aws_api_gateway_rest_api.cat_images.id
  parent_id   = aws_api_gateway_rest_api.cat_images.root_resource_id
  path_part   = "random"
}

# API Gateway method for upload (POST)
resource "aws_api_gateway_method" "upload_post" {
  rest_api_id   = aws_api_gateway_rest_api.cat_images.id
  resource_id   = aws_api_gateway_resource.upload.id
  http_method   = "POST"
  authorization = "NONE"
}

# API Gateway method for random (GET)
resource "aws_api_gateway_method" "random_get" {
  rest_api_id   = aws_api_gateway_rest_api.cat_images.id
  resource_id   = aws_api_gateway_resource.random.id
  http_method   = "GET"
  authorization = "NONE"
}

# API Gateway integration for upload
resource "aws_api_gateway_integration" "upload_lambda" {
  rest_api_id             = aws_api_gateway_rest_api.cat_images.id
  resource_id             = aws_api_gateway_resource.upload.id
  http_method             = aws_api_gateway_method.upload_post.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_images.invoke_arn
}

# API Gateway integration for random
resource "aws_api_gateway_integration" "random_lambda" {
  rest_api_id             = aws_api_gateway_rest_api.cat_images.id
  resource_id             = aws_api_gateway_resource.random.id
  http_method             = aws_api_gateway_method.random_get.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.cat_images.invoke_arn
}

# Lambda permission for upload endpoint
resource "aws_lambda_permission" "api_gateway_upload" {
  statement_id  = "AllowAPIGatewayInvokeUpload"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_images.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_images.execution_arn}/*/*"
}

# Lambda permission for random endpoint
resource "aws_lambda_permission" "api_gateway_random" {
  statement_id  = "AllowAPIGatewayInvokeRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_images.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_images.execution_arn}/*/*"
}

# API Gateway deployment
resource "aws_api_gateway_deployment" "cat_images" {
  rest_api_id = aws_api_gateway_rest_api.cat_images.id

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_resource.upload.id,
      aws_api_gateway_resource.random.id,
      aws_api_gateway_method.upload_post.id,
      aws_api_gateway_method.random_get.id,
      aws_api_gateway_integration.upload_lambda.id,
      aws_api_gateway_integration.random_lambda.id,
    ]))
  }

  lifecycle {
    create_before_destroy = true
  }

  depends_on = [
    aws_api_gateway_integration.upload_lambda,
    aws_api_gateway_integration.random_lambda
  ]
}

# API Gateway stage
resource "aws_api_gateway_stage" "prod" {
  deployment_id = aws_api_gateway_deployment.cat_images.id
  rest_api_id   = aws_api_gateway_rest_api.cat_images.id
  stage_name    = "prod"
}

# Outputs
output "api_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}"
  description = "API Gateway endpoint URL"
}

output "upload_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/upload"
  description = "Upload endpoint URL"
}

output "random_endpoint" {
  value       = "${aws_api_gateway_stage.prod.invoke_url}/random"
  description = "Random cat image endpoint URL"
}

output "s3_bucket_name" {
  value       = aws_s3_bucket.cat_images.bucket
  description = "S3 bucket name for cat images"
}

output "dynamodb_table_name" {
  value       = aws_dynamodb_table.cat_images.name
  description = "DynamoDB table name"
}
