# IAM role for Lambda function
resource "aws_iam_role" "lambda_role" {
  name = "daily_lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# Attach basic Lambda execution policy
resource "aws_iam_role_policy_attachment" "lambda_basic" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_role.name
}

# Lambda function
resource "aws_lambda_function" "daily_function" {
  filename      = "lambda_function.zip"
  function_name = "daily_scheduled_function"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "python3.11"
  timeout       = 60

  source_code_hash = filebase64sha256("lambda_function.zip")

  environment {
    variables = {
      EXECUTION_TIME = "07:00 UTC"
    }
  }
}

# CloudWatch Log Group for Lambda
resource "aws_cloudwatch_log_group" "lambda_logs" {
  name              = "/aws/lambda/${aws_lambda_function.daily_function.function_name}"
  retention_in_days = 14
}

# EventBridge rule to trigger daily at 07:00 UTC
resource "aws_cloudwatch_event_rule" "daily_trigger" {
  name                = "daily-lambda-trigger-0700-utc"
  description         = "Triggers Lambda function daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

# EventBridge target - Lambda function
resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_trigger.name
  target_id = "DailyLambdaTarget"
  arn       = aws_lambda_function.daily_function.arn
}

# Permission for EventBridge to invoke Lambda
resource "aws_lambda_permission" "allow_eventbridge" {
  statement_id  = "AllowExecutionFromEventBridge"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_function.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_trigger.arn
}

