# DynamoDB table for video metadata
resource "aws_dynamodb_table" "video_metadata" {
  name           = "video-metadata-${random_id.suffix.hex}"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "video_id"
  stream_enabled = true
  stream_view_type = "NEW_AND_OLD_IMAGES"

  attribute {
    name = "video_id"
    type = "S"
  }

  attribute {
    name = "upload_date"
    type = "S"
  }

  global_secondary_index {
    name            = "upload_date_index"
    hash_key        = "upload_date"
    projection_type = "ALL"
  }

  tags = {
    Name        = "video-metadata"
    Environment = "production"
  }
}

# ElastiCache Redis cluster for caching
resource "aws_elasticache_subnet_group" "redis" {
  name       = "video-streaming-redis-subnet-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.private_a.id, aws_subnet.private_b.id]
}

resource "aws_elasticache_replication_group" "redis" {
  replication_group_id       = "video-cache-${random_id.suffix.hex}"
  description                = "Redis cache for video streaming platform"
  engine                     = "redis"
  engine_version             = "7.0"
  node_type                  = "cache.t3.micro"
  num_cache_clusters         = 2
  parameter_group_name       = "default.redis7"
  port                       = 6379
  subnet_group_name          = aws_elasticache_subnet_group.redis.name
  security_group_ids         = [aws_security_group.redis.id]
  automatic_failover_enabled = true
  multi_az_enabled           = true
  at_rest_encryption_enabled = true
  transit_encryption_enabled = true

  tags = {
    Name = "video-streaming-cache"
  }
}

# VPC for ElastiCache and other services
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "video-streaming-vpc"
  }
}

# Private subnets for ElastiCache
resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "video-streaming-private-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "video-streaming-private-b"
  }
}

# Data source for availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# Security group for Redis
resource "aws_security_group" "redis" {
  name        = "redis-sg-${random_id.suffix.hex}"
  description = "Security group for Redis cache"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 6379
    to_port     = 6379
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "redis-security-group"
  }
}

# CloudWatch Log Group for application logs
resource "aws_cloudwatch_log_group" "video_streaming" {
  name              = "/aws/video-streaming/${random_id.suffix.hex}"
  retention_in_days = 30

  tags = {
    Name        = "video-streaming-logs"
    Environment = "production"
  }
}

# Output values
output "cloudfront_domain_name" {
  description = "CloudFront distribution domain name"
  value       = aws_cloudfront_distribution.video_distribution.domain_name
}

output "cloudfront_distribution_id" {
  description = "CloudFront distribution ID"
  value       = aws_cloudfront_distribution.video_distribution.id
}

output "s3_bucket_name" {
  description = "S3 bucket name for video content"
  value       = aws_s3_bucket.video_content.id
}

output "route53_zone_id" {
  description = "Route 53 hosted zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "route53_name_servers" {
  description = "Route 53 name servers"
  value       = aws_route53_zone.main.name_servers
}

output "dynamodb_table_name" {
  description = "DynamoDB table name for video metadata"
  value       = aws_dynamodb_table.video_metadata.name
}

output "redis_endpoint" {
  description = "Redis cluster endpoint"
  value       = aws_elasticache_replication_group.redis.primary_endpoint_address
}

