}

# CloudFront Origin Access Control
resource "aws_cloudfront_origin_access_control" "video_oac" {
  name                              = "video-streaming-oac"
  description                       = "Origin Access Control for video streaming platform"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution
resource "aws_cloudfront_distribution" "video_cdn" {
  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Video streaming platform CDN"
  default_root_object = "index.html"
  price_class         = "PriceClass_All"
  aliases             = ["video.${aws_route53_zone.main.name}"]

  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id                = "S3-${aws_s3_bucket.video_content.id}"
    origin_access_control_id = aws_cloudfront_origin_access_control.video_oac.id
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD", "OPTIONS"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy = "redirect-to-https"
    compress               = true

    forwarded_values {
      query_string = false
      headers      = ["Origin", "Access-Control-Request-Headers", "Access-Control-Request-Method"]

      cookies {
        forward = "none"
      }
    }

    min_ttl     = 0
    default_ttl = 3600
    max_ttl     = 86400
  }

  # Cache behavior for video files
  ordered_cache_behavior {
    path_pattern           = "*.mp4"
    allowed_methods        = ["GET", "HEAD", "OPTIONS"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy = "redirect-to-https"
    compress               = false

    forwarded_values {
      query_string = false
      headers      = ["Origin"]

      cookies {
        forward = "none"
      }
    }

    min_ttl     = 0
    default_ttl = 86400
    max_ttl     = 31536000
  }

  # Cache behavior for HLS streaming
  ordered_cache_behavior {
    path_pattern           = "*.m3u8"
    allowed_methods        = ["GET", "HEAD", "OPTIONS"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "S3-${aws_s3_bucket.video_content.id}"
    viewer_protocol_policy = "redirect-to-https"
    compress               = true

    forwarded_values {
      query_string = false
      headers      = ["Origin"]

      cookies {
        forward = "none"
      }
    }

    min_ttl     = 0
    default_ttl = 10
    max_ttl     = 60
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.cdn_cert.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }

  tags = {
    Name        = "video-streaming-cdn"
    Environment = "production"
  }

  depends_on = [aws_acm_certificate_validation.cdn_cert]
}

# Route 53 hosted zone
resource "aws_route53_zone" "main" {
  name = "example-video-streaming.com"

  tags = {
    Name        = "video-streaming-zone"
    Environment = "production"
  }
}

# Route 53 A record for CloudFront distribution
resource "aws_route53_record" "video_cdn" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "video.${aws_route53_zone.main.name}"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_cdn.domain_name
    zone_id                = aws_cloudfront_distribution.video_cdn.hosted_zone_id
    evaluate_target_health = false
  }
}

# Route 53 AAAA record for CloudFront distribution (IPv6)
resource "aws_route53_record" "video_cdn_ipv6" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "video.${aws_route53_zone.main.name}"
  type    = "AAAA"

  alias {
    name                   = aws_cloudfront_distribution.video_cdn.domain_name
    zone_id                = aws_cloudfront_distribution.video_cdn.hosted_zone_id
    evaluate_target_health = false
  }
}

# ACM certificate for CloudFront (must be in us-east-1)
resource "aws_acm_certificate" "cdn_cert" {
  provider          = aws.us_east_1
  domain_name       = "video.${aws_route53_zone.main.name}"
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }

  tags = {
    Name        = "video-streaming-cert"
    Environment = "production"
  }
}

# Route 53 record for ACM certificate validation
resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cdn_cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
