  value       = aws_cloudfront_distribution.video_cdn.id
}

output "s3_bucket_name" {
  description = "S3 bucket name for video content"
  value       = aws_s3_bucket.video_content.id
}

output "route53_zone_id" {
  description = "Route 53 hosted zone ID"
  value       = aws_route53_zone.main.zone_id
}

output "route53_nameservers" {
  description = "Route 53 nameservers"
  value       = aws_route53_zone.main.name_servers
}

output "video_streaming_url" {
  description = "Video streaming URL"
  value       = "https://video.${aws_route53_zone.main.name}"
}

