  description = "VPC ID"
  value       = aws_vpc.main.id
}

output "db_endpoint" {
  description = "PostgreSQL database endpoint"
  value       = aws_db_instance.postgresql.endpoint
}

output "db_password" {
  description = "PostgreSQL database password"
  value       = random_password.db_password.result
  sensitive   = true
}

