resource "aws_subnet" "private_1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = data.aws_availability_zones.available.names[0]

  tags = {
    Name = "postgresql-private-subnet-1"
  }
}

resource "aws_subnet" "private_2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]

  tags = {
    Name = "postgresql-private-subnet-2"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# DB Subnet Group
resource "aws_db_subnet_group" "postgresql" {
  name       = "postgresql-subnet-group"
  subnet_ids = [aws_subnet.private_1.id, aws_subnet.private_2.id]

  tags = {
    Name = "PostgreSQL DB Subnet Group"
  }
}

# Security Group
resource "aws_security_group" "postgresql" {
  name        = "postgresql-sg"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.main.cidr_block]
  }

  egress {
    description = "Allow all outbound traffic"
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "postgresql-security-group"
  }
}

# KMS Key for encryption
resource "aws_kms_key" "postgresql" {
  description             = "KMS key for PostgreSQL RDS encryption"
  deletion_window_in_days = 10
  enable_key_rotation     = true

  tags = {
    Name = "postgresql-kms-key"
  }
}

resource "aws_kms_alias" "postgresql" {
  name          = "alias/postgresql-rds"
  target_key_id = aws_kms_key.postgresql.key_id
}

# Custom Parameter Group
resource "aws_db_parameter_group" "postgresql" {
  name   = "custom-postgresql-params"
  family = "postgres15"

  parameter {
    name  = "log_connections"
    value = "1"
  }

  parameter {
    name  = "log_disconnections"
    value = "1"
  }

  parameter {
    name  = "log_statement"
    value = "all"
  }

  tags = {
    Name = "Custom PostgreSQL Parameter Group"
  }
}

# Random password generation
resource "random_password" "postgresql" {
  length  = 16
  special = true
}

# RDS PostgreSQL Instance
resource "aws_db_instance" "postgresql" {
  identifier     = "protected-postgresql-db"
  engine         = "postgres"
  engine_version = "15.4"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  storage_type          = "gp3"
  storage_encrypted     = true
  kms_key_id            = aws_kms_key.postgresql.arn

  db_name  = "mypostgresdb"
  username = "dbadmin"
  password = random_password.postgresql.result

  multi_az               = true
  db_subnet_group_name   = aws_db_subnet_group.postgresql.name
  vpc_security_group_ids = [aws_security_group.postgresql.id]
  parameter_group_name   = aws_db_parameter_group.postgresql.name

  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "mon:04:00-mon:05:00"

  deletion_protection = true
  skip_final_snapshot = false
  final_snapshot_identifier = "protected-postgresql-db-final-snapshot"

  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]

  tags = {
    Name        = "Protected PostgreSQL RDS"
    Environment = "production"
  }
}
