```hcl
# Random suffix for unique resource naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Random password for database
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# VPC for the RDS instance
resource "aws_vpc" "airbyte_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "airbyte-test-vpc-${random_id.suffix.hex}"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "airbyte_igw" {
  vpc_id = aws_vpc.airbyte_vpc.id

  tags = {
    Name = "airbyte-test-igw-${random_id.suffix.hex}"
  }
}

# Public subnets in different availability zones
resource "aws_subnet" "public_subnet_1" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-1-${random_id.suffix.hex}"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id                  = aws_vpc.airbyte_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[1]
  map_public_ip_on_launch = true

  tags = {
    Name = "airbyte-public-subnet-2-${random_id.suffix.hex}"
  }
}

# Route table for public subnets
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.airbyte_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.airbyte_igw.id
  }

  tags = {
    Name = "airbyte-public-rt-${random_id.suffix.hex}"
  }
}

# Associate route table with public subnets
resource "aws_route_table_association" "public_subnet_1_association" {
  subnet_id      = aws_subnet.public_subnet_1.id
  route_table_id = aws_route_table.public_rt.id
}

resource "aws_route_table_association" "public_subnet_2_association" {
  subnet_id      = aws_subnet.public_subnet_2.id
  route_table_id = aws_route_table.public_rt.id
}

# Data source for available availability zones
data "aws_availability_zones" "available" {
  state = "available"
}

# DB Subnet Group
resource "aws_db_subnet_group" "airbyte_subnet_group" {
  name       = "airbyte-test-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]

  tags = {
    Name = "airbyte-test-subnet-group-${random_id.suffix.hex}"
  }
}

# Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "airbyte-rds-sg-${random_id.suffix.hex}"
  description = "Security group for Airbyte test RDS instance"
  vpc_id      = aws_vpc.airbyte_vpc.id

  ingress {
    description = "PostgreSQL access"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "airbyte-rds-sg-${random_id.suffix.hex}"
  }
}

# RDS PostgreSQL 15 instance
resource "aws_db_instance" "airbyte_postgres" {
  identifier     = "airbyte-test-postgres-${random_id.suffix.hex}"
  engine         = "postgres"
  engine_version = "15.4"
  instance_class = "db.t3.micro"

  allocated_storage     = 20
  max_allocated_storage = 100
  storage_type          = "gp3"
  storage_encrypted     = true

  db_name  = "airbytetest"
  username = "airbyte_admin"
  password = random_password.db_password.result

  db_subnet_group_name   = aws_db_subnet_group.airbyte_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible    = true

  backup_retention_period = 7
  backup_window          = "03:00-04:00"
  maintenance_window     = "mon:04:00-mon:05:00"

  auto_minor_version_upgrade = true
  deletion_protection        = false
  skip_final_snapshot        = true

  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]

  tags = {
    Name        = "airbyte-test-postgres-${random_id.suffix.hex}"
    Purpose     = "Airbyte Connector Testing"
    Environment = "Test"
  }
}

# Outputs
output "rds_endpoint" {
  description = "RDS instance endpoint"
  value       = aws_db_instance.airbyte_postgres.endpoint
}

output "rds_database_name" {
  description = "Database name"
  value       = aws_db_instance.airbyte_postgres.db_name
}

output "rds_username" {
  description = "Database username"
  value       = aws_db_instance.airbyte_postgres.username
  sensitive   = true
}

output "rds_password" {
  description = "Database password"
  value       = random_password.db_password.result
  sensitive   = true
}

output "rds_port" {
  description = "Database port"
  value       = aws_db_instance.airbyte_postgres.port
}
```

