extracted_code:
# S3 bucket for long-term data retention and backups
resource "aws_s3_bucket" "backup" {
  bucket = "long-term-backup-${random_id.suffix.hex}"
}

resource "random_id" "suffix" {
  byte_length = 8
}

# Enable versioning for data protection
resource "aws_s3_bucket_versioning" "backup" {
  bucket = aws_s3_bucket.backup.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Lifecycle policy for cost optimization
resource "aws_s3_bucket_lifecycle_configuration" "backup" {
  bucket = aws_s3_bucket.backup.id

  rule {
    id     = "transition-to-glacier"
    status = "Enabled"

    transition {
      days          = 90
      storage_class = "GLACIER"
    }

    transition {
      days          = 180
      storage_class = "DEEP_ARCHIVE"
    }

    noncurrent_version_transition {
      noncurrent_days = 30
      storage_class   = "GLACIER"
    }
  }
}

# Enable server-side encryption
resource "aws_s3_bucket_server_side_encryption_configuration" "backup" {
  bucket = aws_s3_bucket.backup.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

# Block public access
resource "aws_s3_bucket_public_access_block" "backup" {
  bucket = aws_s3_bucket.backup.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

# Enable logging
resource "aws_s3_bucket" "log_bucket" {
  bucket = "backup-logs-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_logging" "backup" {
  bucket = aws_s3_bucket.backup.id

  target_bucket = aws_s3_bucket.log_bucket.id
  target_prefix = "log/"
}

# Backup vault for AWS Backup service
resource "aws_backup_vault" "backup_vault" {
  name = "long-term-backup-vault"
}

# KMS key for backup encryption
resource "aws_kms_key" "backup" {
  description             = "KMS key for backup encryption"
  deletion_window_in_days = 10
}

resource "aws_kms_alias" "backup" {
  name          = "alias/backup-key"
  target_key_id = aws_kms_key.backup.key_id
}

