# Create SNS topic for Glacier vault notifications
resource "aws_sns_topic" "glacier_notifications" {
  name = "glacier-vault-notifications"
}

# Create Glacier vault
resource "aws_glacier_vault" "main" {
  name = "main-glacier-vault"

  notification {
    sns_topic = aws_sns_topic.glacier_notifications.arn
    events    = ["ArchiveRetrievalCompleted", "InventoryRetrievalCompleted"]
  }

  tags = {
    Name        = "Main Glacier Vault"
    Environment = "production"
  }
}

# Create IAM role for DLM
resource "aws_iam_role" "dlm_lifecycle_role" {
  name = "dlm-lifecycle-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to DLM role
resource "aws_iam_role_policy" "dlm_lifecycle" {
  name = "dlm-lifecycle-policy"
  role = aws_iam_role.dlm_lifecycle_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateSnapshot",
          "ec2:CreateSnapshots",
          "ec2:DeleteSnapshot",
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:DescribeInstances"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateTags"
        ]
        Resource = "arn:aws:ec2:*::snapshot/*"
      }
    ]
  })
}

# Create DLM lifecycle policy for EBS snapshots with Glacier archive tier
resource "aws_dlm_lifecycle_policy" "glacier_archive" {
  description        = "EBS snapshot lifecycle policy with Glacier archival"
  execution_role_arn = aws_iam_role.dlm_lifecycle_role.arn
  state              = "ENABLED"

  policy_details {
    resource_types = ["VOLUME"]

    schedule {
      name = "Daily snapshots with Glacier archival"

      create_rule {
        interval      = 24
        interval_unit = "HOURS"
        times         = ["03:00"]
      }

      retain_rule {
        count = 30
      }

      tags_to_add = {
        SnapshotCreator = "DLM"
        GlacierArchive  = "true"
      }

      copy_tags = true

      # Archive snapshots to Glacier after 7 days
      deprecate_rule {
        interval      = 7
        interval_unit = "DAYS"
      }
    }

    target_tags = {
      Backup = "true"
    }
  }

  tags = {
    Name        = "Glacier Archive Policy"
    Environment = "production"
  }
}

# Output the Glacier vault ARN and name
output "glacier_vault_arn" {
  description = "ARN of the Glacier vault"
  value       = aws_glacier_vault.main.arn
}

output "glacier_vault_name" {
  description = "Name of the Glacier vault"
  value       = aws_glacier_vault.main.name
}

output "dlm_policy_id" {
  description = "ID of the DLM lifecycle policy"
  value       = aws_dlm_lifecycle_policy.glacier_archive.id
}

